from __future__ import annotations

import json
import os
import shutil
import subprocess
import sys
from pathlib import Path
from typing import Any


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = [
    Path("apps/admin-dashboard"),
    Path("apps/integration-console"),
    Path("apps/patient-portal"),
    Path("apps/provider-portal"),
    Path("apps/public-website"),
]
REQUIRED_DIRS = [
    Path("apps"),
    Path("services"),
    Path("packages"),
    Path("scripts"),
    Path("database"),
    Path("database/migrations"),
    Path("infrastructure/docker"),
    Path("infrastructure/helm"),
    Path("infrastructure/kubernetes"),
]
SKIP_PARTS = {
    ".git",
    ".pytest_cache",
    "__pycache__",
    "build",
    "coverage",
    "dist",
    "node_modules",
}


def display(path: Path) -> str:
    return path.relative_to(ROOT).as_posix()


def run(command: list[str], cwd: Path = ROOT) -> None:
    location = display(cwd) if cwd != ROOT else "."
    print(f"+ ({location}) {' '.join(command)}")
    subprocess.run(command, cwd=cwd, check=True)


def skip(message: str) -> None:
    print(f"skip: {message}")


def has_tool(name: str) -> bool:
    return shutil.which(name) is not None


def should_skip_path(path: Path) -> bool:
    return any(part in SKIP_PARTS for part in path.parts)


def require_file(path: Path) -> None:
    if not (ROOT / path).is_file():
        raise FileNotFoundError(f"required file is missing: {path.as_posix()}")


def require_dir(path: Path) -> None:
    if not (ROOT / path).is_dir():
        raise FileNotFoundError(f"required directory is missing: {path.as_posix()}")


def verify_project_layout() -> None:
    for path in REQUIRED_DIRS:
        require_dir(path)
    for app in FRONTEND_APPS:
        require_dir(app)
        require_file(app / "package.json")
        require_file(app / "package-lock.json")
        require_file(app / "tsconfig.json")
        require_file(app / "vite.config.ts")
    require_file(Path("package.json"))
    require_file(Path("package-lock.json"))
    require_file(Path("database/schema.sql"))
    require_file(Path("docker-compose.yml"))
    print("verified required project directories and frontend lockfiles")


def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if should_skip_path(path):
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files")


def is_helm_template(path: Path) -> bool:
    if "templates" not in path.parts:
        return False
    return any((parent / "Chart.yaml").is_file() for parent in path.parents)


def load_yaml(path: Path) -> Any:
    import yaml

    with path.open(encoding="utf-8") as handle:
        return yaml.safe_load(handle)


def validate_yaml() -> None:
    try:
        import yaml  # noqa: F401
    except Exception as exc:
        skip(f"yaml validation requires PyYAML ({exc})")
        return

    count = 0
    skipped_templates = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if should_skip_path(path):
                continue
            if is_helm_template(path):
                skipped_templates += 1
                continue
            load_yaml(path)
            count += 1
    print(
        f"validated {count} non-template yaml files "
        f"({skipped_templates} helm templates skipped)"
    )


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def verify_go_sdk() -> None:
    sdk_dir = ROOT / "packages/sdk-go"
    require_dir(Path("packages/sdk-go"))
    require_file(Path("packages/sdk-go/go.mod"))
    if not has_tool("go"):
        skip("go sdk tests require go")
        return
    run(["go", "test", "./..."], cwd=sdk_dir)


def verify_helm() -> None:
    chart_dirs = sorted(path.parent for path in ROOT.rglob("Chart.yaml"))
    if not chart_dirs:
        raise FileNotFoundError("no Helm Chart.yaml files found")

    for chart_dir in chart_dirs:
        chart = load_yaml(chart_dir / "Chart.yaml")
        if not isinstance(chart, dict):
            raise ValueError(f"{display(chart_dir / 'Chart.yaml')} must be a mapping")
        for key in ("apiVersion", "name", "version"):
            if not chart.get(key):
                raise ValueError(f"{display(chart_dir / 'Chart.yaml')} missing {key}")
    print(f"validated {len(chart_dirs)} helm chart metadata files")

    if not has_tool("helm"):
        skip("helm lint requires helm")
        return
    for chart_dir in chart_dirs:
        run(["helm", "lint", str(chart_dir)])


def verify_database() -> None:
    require_file(Path("database/schema.sql"))
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    if not migrations:
        raise FileNotFoundError("database/migrations has no sql migrations")
    print(f"verified database schema and {len(migrations)} migration files are present")

    database_url = os.environ.get("HEALTHBRIDGE_VERIFY_DATABASE_URL")
    if not database_url:
        skip("psql schema load requires HEALTHBRIDGE_VERIFY_DATABASE_URL")
        return
    if not has_tool("psql"):
        skip("psql schema load requires psql")
        return
    run(
        [
            "psql",
            database_url,
            "--set",
            "ON_ERROR_STOP=1",
            "--file",
            str(ROOT / "database/schema.sql"),
        ]
    )


def verify_docker_inputs() -> None:
    dockerfiles = sorted((ROOT / "services").glob("*/Dockerfile"))
    if not dockerfiles:
        raise FileNotFoundError("no service Dockerfiles found")
    for dockerfile in dockerfiles:
        if not (dockerfile.parent / "app.py").is_file():
            raise FileNotFoundError(
                f"{display(dockerfile)} has no adjacent app.py build input"
            )
    require_file(Path("docker-compose.yml"))
    print(f"verified docker build inputs for {len(dockerfiles)} services")

    if not has_tool("docker"):
        skip("docker compose config requires docker")
        return
    try:
        run(["docker", "compose", "config", "--quiet"])
    except subprocess.CalledProcessError:
        skip("docker compose config unavailable or docker daemon is not reachable")


def main() -> None:
    verify_project_layout()
    run([sys.executable, "-m", "compileall", "-q", "services", "packages", "scripts"])
    run([sys.executable, "-m", "pytest", "-q"])
    validate_json()
    validate_yaml()
    run_services()
    run_frontends()
    verify_go_sdk()
    verify_helm()
    verify_database()
    verify_docker_inputs()


if __name__ == "__main__":
    main()

