    require_file(Path("package.json"))
    require_file(Path("package-lock.json"))
    require_file(Path("database/schema.sql"))
    require_file(Path("docker-compose.yml"))
    print("verified required project directories and frontend lockfiles")


def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if should_skip_path(path):
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files")


def is_helm_template(path: Path) -> bool:
    if "templates" not in path.parts:
        return False
    return any((parent / "Chart.yaml").is_file() for parent in path.parents)


def load_yaml(path: Path) -> Any:
    import yaml

    with path.open(encoding="utf-8") as handle:
        return yaml.safe_load(handle)


def validate_yaml() -> None:
    try:
        import yaml  # noqa: F401
    except Exception as exc:
        skip(f"yaml validation requires PyYAML ({exc})")
        return

    count = 0
    skipped_templates = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if should_skip_path(path):
                continue
            if is_helm_template(path):
                skipped_templates += 1
                continue
            load_yaml(path)
            count += 1
    print(
        f"validated {count} non-template yaml files "
        f"({skipped_templates} helm templates skipped)"
    )


